{"summary": "Retrieve failure likelihood", "description": "Retrieve the probability of potential failures for system components based on predictive models.", "responses": {"200": {"description": "Successfully retrieved failure likelihood data.", "content": {"application/json": {"schema": {"type": "array", "items": {"type": "object", "properties": {"component": {"type": "string", "description": "Name or ID of the component."}, "failureProbability": {"type": "number", "format": "float", "description": "The likelihood of failure as a percentage."}, "lastAnalyzed": {"type": "string", "format": "date-time", "description": "Timestamp when this likelihood was last analyzed."}}}}}}}, "500": {"description": "Server error while retrieving failure likelihood data."}}}

Endpoint: PUT /maintenance-schedule/{id}
Specification:
{"summary": "Update maintenance schedule entry", "description": "Modify an existing scheduled maintenance activity by its ID.", "parameters": [{"in": "path", "name": "id", "required": true, "schema": {"type": "string"}, "description": "Unique identifier of the schedule to update."}], "requestBody": {"required": true, "content": {"application/json": {"schema": {"type": "object", "properties": {"activity": {"type": "string", "description": "Updated description of the maintenance activity."}, "date": {"type": "string", "format": "date", "description": "Updated scheduled date for the maintenance activity."}, "status": {"type": "string", "enum": ["Pending", "Completed", "In Progress"], "description": "Updated status of the maintenance activity."}}}}}}, "responses": {"200": {"description": "Successfully updated the maintenance schedule entry."}, "400": {"description": "Invalid input format or missing fields."}, "404": {"description": "Maintenance schedule entry with the given ID not found."}, "500": {"description": "Server error while updating the maintenance schedule entry."}}}

Endpoint: DELETE /incident-report/{id}
Specification:
{"summary": "Delete an incident report", "description": "Remove a specific incident report by its unique ID.", "parameters": [{"in": "path", "name": "id", "required": true, "schema": {"type": "string"}, "description": "Unique identifier of the incident report to delete."}], "responses": {"200": {"description": "Successfully deleted the incident report."}, "404": {"description": "Incident report with the given ID not found."}, "500": {"description": "Server error while deleting the incident report."}}}

Endpoint: GET /equipment-status
Specification:
{"summary": "Retrieve equipment status", "description": "Obtain the current status and performance metrics of all monitored equipment.", "responses": {"200": {"description": "Successfully retrieved the equipment status and metrics.", "content": {"application/json": {"schema": {"type": "array", "items": {"type": "object", "properties": {"equipmentId": {"type": "string", "description": "Identifier of the equipment."}, "status": {"type": "string", "description": "Current operational status of the equipment."}, "metrics": {"type": "object", "description": "Performance metrics collected from the equipment."}}}}}}}, "500": {"description": "Server error while retrieving equipment status."}}}

Endpoint: GET /alerts
Specification:
{"summary": "Access active alerts", "description": "Retrieve all currently active alerts and warnings related to system performance.", "responses": {"200": {"description": "Successfully accessed active alerts and warnings.", "content": {"application/json": {"schema": {"type": "array", "items": {"type": "object", "properties": {"alertId": {"type": "string", "description": "Unique identifier of the alert."}, "type": {"type": "string", "description": "Type of alert, such as warning or critical issue."}, "message": {"type": "string", "description": "Detailed information about the alert."}, "timestamp": {"type": "string", "format": "date-time", "description": "Timestamp of when the alert was triggered."}}}}}}}, "500": {"description": "Server error while retrieving active alerts."}}}

Endpoint: POST /custom-query
Specification:
{"summary": "Execute custom analytics query", "description": "Run custom analytics queries on existing datasets to derive specific insights.", "requestBody": {"required": true, "content": {"application/json": {"schema": {"type": "object", "properties": {"query": {"type": "string", "description": "Custom analytics query string."}}, "required": ["query"]}}}}, "responses": {"200": {"description": "Successfully executed the custom query and retrieved the results.", "content": {"application/json": {"schema": {"type": "object", "description": "Query results in JSON format."}}}}, "400": {"description": "Invalid query syntax or request format."}, "500": {"description": "Server error while executing the custom query."}}}
